#!/usr/bin/env python3
"""
数字恶臭化生成器 — 通用搜索版 (v2)
====================================
使用 114514 系列数字池，通过通用 DFS/DP 搜索算法，
自动拆解任意目标数字为恶臭风格数学表达式。

约束：任何运算不产生值为 0 的结果或中间值。
表达式中的数字不出现 0 数码位（不含池中自带 0 的超级数）。

搜索策略：
  A - 直接加减组合拆解
  B - 114514 × k + r（基础乘法拆解）
  C - 1145140 × k + r（大数乘法拆解）
  D - 514 × a + 114 × b + r（双臭混合）
  E - 14514 × k + r（近亲乘法拆解）
  F - 除法还原：(a × b) ÷ c ± r
  G - 114514 进制展开（学院派）

用法：
    python3 generate.py <数字>
    python3 generate.py 20070521

灵感源自 lab.magiconch.com 的数字恶臭化工具。
"""

import sys
import re
import math
import random
from functools import lru_cache

# =====================================================================
# 第一节：恶臭数字池
# =====================================================================

# 基础数集（不含 0 数码位）
BASE_POOL = [1, 4, 5, 11, 14, 15, 51, 54]

# 扩展数集（不含 0 数码位）
EXT_POOL = [114, 514, 1145, 1451, 14514, 114514]

# 巨型数（含 0 数码位的超级数，用于大数场景）
MEGA_POOL = [1145140, 1919810, 1145141919810]

# 全量池（按值排序）
ALL_POOL = sorted(set(BASE_POOL + EXT_POOL))
ALL_POOL_MEGA = sorted(set(ALL_POOL + MEGA_POOL))

# 不含 0 数码位的纯池
CLEAN_POOL = sorted(ALL_POOL)

# =====================================================================
# 第二节：辅助函数
# =====================================================================

def has_digit_zero(n):
    """数字的十进制表示中是否含有 0 数码位"""
    return '0' in str(abs(n))

def eval_expr(expr_str):
    """安全计算表达式值（替换 Unicode 数学符号为 ASCII）"""
    s = expr_str.replace('×', '*').replace('−', '-').replace('÷', '/')
    s = s.replace('＋', '+')
    return eval(s)

def verify_no_zero_value(expr_str):
    """验证表达式计算不产生零值"""
    # 先快速检查是否有 a − a 模式
    if re.search(r'(?<!\d)(\d+)\s*−\s*\1(?!\d)', expr_str):
        return False
    try:
        return eval_expr(expr_str) != 0
    except:
        return False

def count_standalone(expr_str, target_num):
    """统计表达式中独立出现 target_num 的次数（非数字前缀）"""
    pattern = r'(?<!\d)' + str(target_num) + r'(?!\d)'
    return len(re.findall(pattern, expr_str))

def simplify_terms(terms):
    """合并正负抵消的同类项，简化表达式"""
    net = {}
    for sign, num in terms:
        net[num] = net.get(num, 0) + (1 if sign == '+' else -1)
    result = []
    for num, count in sorted(net.items(), reverse=True):
        if count > 0:
            result.extend([('+', num)] * count)
        elif count < 0:
            result.extend([('-', num)] * abs(count))
    return result

def terms_to_expr(terms):
    """将 [(sign, num), ...] 转为表达式字符串"""
    if not terms:
        return ""
    parts = []
    for i, (sign, num) in enumerate(terms):
        if i == 0:
            parts.append(f"{'' if sign == '+' else '−'}{num}")
        else:
            parts.append(f" {'+' if sign == '+' else '−'} {num}")
    return "".join(parts)

def term_sum(terms):
    """计算 terms 代数和"""
    return sum(v if s == '+' else -v for s, v in terms)

def format_expr_as_result(expr_str, target):
    """格式化为 N = expr 形式"""
    return f"{target} = {expr_str}"

# =====================================================================
# 第三节：核心分解算法（带缓存的 DP + DFS）
# =====================================================================

@lru_cache(maxsize=10000)
def decompose_sum(target, max_terms=8, pool=None):
    """
    DP/DFS：将 target 分解为 pool 中正数的和。
    返回 [n1, n2, ...] 列表，所有项为正，和为 target。
    返回 None 表示无解。
    """
    if pool is None:
        pool_tuple = tuple(ALL_POOL)
    else:
        pool_tuple = tuple(sorted(pool))

    target = abs(target)
    if target == 0:
        return []
    if target in pool_tuple:
        return [target]
    if max_terms <= 1:
        return None

    best = None
    for n in reversed(pool_tuple):
        if n > target or n == 0:
            continue
        rest = decompose_sum(target - n, max_terms - 1, pool_tuple)
        if rest is not None:
            cand = [n] + rest
            if best is None or len(cand) < len(best):
                best = cand
            if len(cand) <= 2:
                return cand
    return best


@lru_cache(maxsize=10000)
def decompose_mixed(target, max_terms=6, pool=None):
    """
    DP/DFS：将 target 分解为 pool 中带符号数的代数和。
    返回 [(sign, num), ...]，最终代数和 = target。
    不允许出现相同值相消（会得到 0）。
    返回 None 表示无解。
    """
    if pool is None:
        pool_tuple = tuple(ALL_POOL)
    else:
        pool_tuple = tuple(sorted(pool))

    target = int(target)
    if target == 0:
        return []

    # 直接命中
    if target in pool_tuple:
        return [('+', target)]
    if -target in pool_tuple:
        return [('-', target)]

    if max_terms <= 1:
        return None

    best = None

    for n in reversed(pool_tuple):
        if n == 0:
            continue

        # ---- 分支 1：n + rest = target => rest = target - n ----
        remaining = target - n
        if remaining != 0:
            rest = decompose_mixed(remaining, max_terms - 1, pool_tuple)
            if rest is not None:
                cand = [('+', n)] + rest
                # 检查是否产生零（无 a − a 模式）
                if not has_self_cancel(cand):
                    if best is None or len(cand) < len(best):
                        best = cand
                    if len(cand) <= 2:
                        return cand

        # ---- 分支 2：n - rest = target => rest = n - target ----
        if n > target:
            remaining2 = n - target
            if remaining2 != 0:
                rest2 = decompose_mixed(remaining2, max_terms - 1, pool_tuple)
                if rest2 is not None:
                    cand2 = [('+', n)]
                    for s, v in rest2:
                        # 翻转符号：如果 rest2 是 +v，那么 n - (+v) → 这里变成 −v
                        cand2.append(('-' if s == '+' else '+', v))
                    if not has_self_cancel(cand2):
                        if best is None or len(cand2) < len(best):
                            best = cand2
                        if len(cand2) <= 2:
                            return cand2

    return best


def has_self_cancel(terms):
    """检查是否有 a − a 模式（会产生 0）"""
    net = {}
    for sign, num in terms:
        key = (sign, num)
        net[key] = net.get(key, 0) + 1
    for (s1, v1), c1 in net.items():
        if v1 == 0:
            return True
        # 检查是否存在相反的符号配对
        opposite_sign = '-' if s1 == '+' else '+'
        c2 = net.get((opposite_sign, v1), 0)
        if c1 > 0 and c2 > 0:
            # 有 +v 和 -v 同时存在 → 会互相抵消
            return True
    return False


def decompose_multiplicative(target, pool=None):
    """
    寻找 target = a × b + r 形式，其中 a, b 来自 pool。
    返回 (a, b, r, expr_format) 或 None。
    """
    if pool is None:
        p = ALL_POOL
    else:
        p = sorted(pool)

    candidates = []
    for a in reversed(p):
        if a == 0 or a > target:
            continue
        q = target // a
        r = target % a
        if q == 0:
            continue
        if q in p:
            candidates.append((a, q, r, f"{a} × {q}{' + ' + str(r) if r > 0 else ''}"))
        # 尝试 q 的分解
        rest = decompose_mixed(q, max_terms=4, pool=tuple(p))
        if rest is not None and len(rest) <= 3:
            q_expr = terms_to_expr(rest)
            r_part = f" + {r}" if r > 0 else ""
            candidates.append((a, q, r, f"{a} × ({q_expr}){r_part}"))

    if not candidates:
        return None

    # 按恶臭潜力排序：a=114514最佳，其次514，再114...
    def rank(c):
        a, _, _, _ = c
        if a == 114514:
            return 0
        if a == 514:
            return 1
        if a == 114:
            return 2
        if a == 14514:
            return 3
        return 10

    candidates.sort(key=rank)
    return candidates[0]


# =====================================================================
# 第四节：各搜索策略
# =====================================================================

def strategy_A_direct_sum(target):
    """
    【策略 A】直接加减拆解
    将 target 拆解为 pool 数字的代数和（带符号）
    """
    if target in ALL_POOL:
        return [(f"{target}（本身就是恶臭数字！）", target)]

    results = []

    # A1: 纯加法分解（多个正数之和）
    sum_decomp = decompose_sum(target, max_terms=8)
    if sum_decomp:
        expr = " + ".join(str(n) for n in sum_decomp)
        if verify_no_zero_value(expr):
            results.append((expr, target))

    # A2: 带符号分解（正数为主 + 少量修正）
    mixed = decompose_mixed(target, max_terms=6)
    if mixed:
        expr = terms_to_expr(mixed)
        if verify_no_zero_value(expr):
            results.append((expr, target))

    # A3: 另一个方向的混合尝试
    # 用 114 或 514 先拉近，再调整
    for base in [114, 514, 1145]:
        if base > target:
            # base - adj = target
            adj = base - target
            rest = decompose_sum(adj, max_terms=4)
            if rest and adj > 0:
                expr = f"{base} − {' − '.join(str(n) for n in rest)}"
                final = target
                if verify_no_zero_value(expr):
                    results.append((expr, final))
        else:
            adj = target - base
            rest = decompose_sum(adj, max_terms=5)
            if rest:
                expr = f"{base} + {' + '.join(str(n) for n in rest)}"
                if verify_no_zero_value(expr):
                    results.append((expr, target))

    return results


def strategy_B_114514_mul(target):
    """
    【策略 B】114514 × k + r
    优先使用 114514 作为乘法基数
    """
    if target <= 114514:
        return []

    results = []
    base = 114514
    k = target // base
    r = target % base

    # B1: 直接 k 和 r
    k_str = str(k)
    r_str = f" + {r}" if r > 0 else ""
    expr = f"114514 × {k}{r_str}"
    if verify_no_zero_value(expr):
        results.append((expr, target))

    # B2: 分解 k（拆成 sum）
    k_decomp = decompose_sum(k, max_terms=5)
    if k_decomp:
        k_expr = " + ".join(str(n) for n in k_decomp)
        r_part = f" + {r}" if r > 0 else ""
        expr = f"114514 × ({k_expr}){r_part}"
        if verify_no_zero_value(expr):
            results.append((expr, target))

    # B3: 分解 k（带符号混合）
    k_mixed = decompose_mixed(k, max_terms=4)
    if k_mixed:
        k_expr = terms_to_expr(k_mixed)
        r_part = f" + {r}" if r > 0 else ""
        expr = f"114514 × ({k_expr}){r_part}"
        if verify_no_zero_value(expr):
            results.append((expr, target))

    # B4: 分解 r
    if r > 0:
        r_decomp = decompose_mixed(r, max_terms=4)
        if r_decomp:
            r_expr = terms_to_expr(r_decomp)
            expr = f"114514 × {k} + {r_expr}"
            if verify_no_zero_value(expr):
                results.append((expr, target))

        # B5: k 和 r 都分解
        k_decomp2 = decompose_mixed(k, max_terms=3)
        r_decomp2 = decompose_mixed(r, max_terms=4)
        if k_decomp2 and r_decomp2:
            k_expr2 = terms_to_expr(k_decomp2)
            r_expr2 = terms_to_expr(r_decomp2)
            expr = f"114514 × ({k_expr2}) + {r_expr2}"
            if verify_no_zero_value(expr):
                results.append((expr, target))

    # B6: 尝试 k = k - 1, r = r + 114514（如果 k > 1）
    if k > 1:
        k2 = k - 1
        r2 = r + base
        k_decomp3 = decompose_mixed(k2, max_terms=3)
        r_decomp3 = decompose_mixed(r2, max_terms=4)
        if k_decomp3 and r_decomp3:
            k_expr3 = terms_to_expr(k_decomp3)
            r_expr3 = terms_to_expr(r_decomp3)
            expr = f"114514 × ({k_expr3}) + {r_expr3}"
            if verify_no_zero_value(expr):
                results.append((expr, target))

    return results


def strategy_C_1145140_mul(target):
    """
    【策略 C】1145140 × k + r（超大数场景）
    """
    if target <= 1145140:
        return []

    results = []
    base = 1145140
    k = target // base
    r = target % base

    # C1: 直接
    r_str = f" + {r}" if r > 0 else ""
    expr = f"1145140 × {k}{r_str}"
    if verify_no_zero_value(expr):
        results.append((expr, target))

    # C2: 分解 k
    k_decomp = decompose_mixed(k, max_terms=4)
    if k_decomp:
        k_expr = terms_to_expr(k_decomp)
        r_part = f" + {r}" if r > 0 else ""
        expr = f"1145140 × ({k_expr}){r_part}"
        if verify_no_zero_value(expr):
            results.append((expr, target))

    # C3: 分解 r
    if r > 0:
        r_decomp = decompose_mixed(r, max_terms=5)
        if r_decomp:
            r_expr = terms_to_expr(r_decomp)
            expr = f"1145140 × {k} + {r_expr}"
            if verify_no_zero_value(expr):
                results.append((expr, target))

        k_decomp2 = decompose_mixed(k, max_terms=3)
        r_decomp2 = decompose_mixed(r, max_terms=4)
        if k_decomp2 and r_decomp2:
            k_expr2 = terms_to_expr(k_decomp2)
            r_expr2 = terms_to_expr(r_decomp2)
            expr = f"1145140 × ({k_expr2}) + {r_expr2}"
            if verify_no_zero_value(expr):
                results.append((expr, target))

    return results


def strategy_D_514_114_mix(target):
    """
    【策略 D】514 × a + 114 × b + r
    双臭混合，最大化 114/514 出现频率
    """
    results = []

    # D1: 贪婪找系数
    for a in range(1, min(target // 514 + 1, 50)):
        rem_after_514 = target - 514 * a
        if rem_after_514 < 0:
            break
        for b in range(0, min(rem_after_514 // 114 + 1, 50)):
            r = rem_after_514 - 114 * b
            if r == 0:
                expr = f"514 × {a} + 114 × {b}"
                if verify_no_zero_value(expr):
                    results.append((expr, target))
            elif r > 0 and r < 5000:
                r_decomp = decompose_mixed(r, max_terms=4)
                if r_decomp:
                    r_expr = terms_to_expr(r_decomp)
                    expr = f"514 × {a} + 114 × {b} + {r_expr}"
                    if verify_no_zero_value(expr):
                        results.append((expr, target))

            # 如果 a 或 b 本身可分解，更臭
            if a <= 200 and b <= 200:
                a_decomp = decompose_mixed(a, max_terms=3)
                b_decomp = decompose_mixed(b, max_terms=3)
                if a_decomp and b_decomp:
                    a_expr = terms_to_expr(a_decomp)
                    b_expr = terms_to_expr(b_decomp)
                    r2 = target - 514 * a - 114 * b
                    if r2 == 0:
                        expr = f"514 × ({a_expr}) + 114 × ({b_expr})"
                        if verify_no_zero_value(expr):
                            results.append((expr, target))
                    elif r2 > 0:
                        r_decomp2 = decompose_mixed(r2, max_terms=3)
                        if r_decomp2:
                            r_expr2 = terms_to_expr(r_decomp2)
                            expr = f"514 × ({a_expr}) + 114 × ({b_expr}) + {r_expr2}"
                            if verify_no_zero_value(expr):
                                results.append((expr, target))

    # D2: 反过来 114 × b - 514 × a
    for b in range(1, min(target // 114 + 1, 50)):
        val = 114 * b
        if val > target:
            diff = val - target
            r_decomp = decompose_mixed(diff, max_terms=4)
            if r_decomp:
                r_expr = terms_to_expr(r_decomp)
                expr = f"114 × {b} − ({r_expr})"
                full_expr = f"114 × {b} − {r_expr}"
                if verify_no_zero_value(full_expr):
                    results.append((full_expr, target))

    return results


def strategy_E_14514_mul(target):
    """
    【策略 E】14514 × k + r（近亲乘法变体）
    """
    if target <= 14514:
        return []

    results = []
    base = 14514
    k = target // base
    r = target % base

    # E1
    r_str = f" + {r}" if r > 0 else ""
    expr = f"14514 × {k}{r_str}"
    if verify_no_zero_value(expr):
        results.append((expr, target))

    # E2: 分解 k
    k_decomp = decompose_mixed(k, max_terms=4)
    if k_decomp:
        k_expr = terms_to_expr(k_decomp)
        r_part = f" + {r}" if r > 0 else ""
        expr = f"14514 × ({k_expr}){r_part}"
        if verify_no_zero_value(expr):
            results.append((expr, target))

    return results


def strategy_F_division(target):
    """
    【策略 F】除法还原：(a × b) ÷ c ± r
    利用 114514 × k 能被某个 pool 数整除来构造
    """
    results = []
    for a in [114514, 14514, 1145, 514, 114]:
        if a > target:
            continue
        # 尝试 N = (a × b) / d
        for d in BASE_POOL + [114, 514]:
            if d == 0:
                continue
            # 找 b 使得 a × b 接近 target × d
            approx = target * d // a
            for b in range(max(1, approx - 5), approx + 6):
                prod = a * b
                if prod % d != 0:
                    continue
                val = prod // d
                r = target - val
                if r == 0:
                    expr = f"({a} × {b}) ÷ {d}"
                    if verify_no_zero_value(expr):
                        results.append((expr, target))
                elif abs(r) < 10000:
                    r_decomp = decompose_mixed(abs(r), max_terms=3)
                    if r_decomp:
                        r_expr = terms_to_expr(r_decomp)
                        sign = '+'
                        if r < 0:
                            sign = '−'
                            r_expr = terms_to_expr([('+' if s == '-' else '-', v) for s, v in r_decomp])
                        expr = f"({a} × {b}) ÷ {d} {sign} {r_expr}"
                        if verify_no_zero_value(expr):
                            results.append((expr, target))

    return results


def strategy_G_114514_base(target):
    """
    【策略 G】114514 进制展开（学院派）
    将 target 以 114514 为基展开，每位用 pool 数字表示
    """
    if target < 114514:
        return []

    results = []
    base = 114514

    # 计算进制表示
    n = target
    digits = []
    while n > 0:
        digits.append(n % base)
        n //= base

    # 构建表达式
    parts = []
    valid = True
    for i, d in enumerate(digits):
        if d == 0:
            valid = False
            break
        if d in ALL_POOL:
            if i == 0:
                parts.append(str(d))
            elif i == 1:
                parts.append(f"{d} × 114514")
            else:
                parts.append(f"{d} × 114514^{i}")
        else:
            # 尝试分解 d
            d_decomp = decompose_sum(d, max_terms=3)
            if d_decomp:
                d_expr = " + ".join(str(n) for n in d_decomp)
                if i == 0:
                    parts.append(f"({d_expr})")
                elif i == 1:
                    parts.append(f"({d_expr}) × 114514")
                else:
                    parts.append(f"({d_expr}) × 114514^{i}")
            else:
                valid = False
                break

    if valid and parts:
        expr = " + ".join(reversed(parts))
        if verify_no_zero_value(expr):
            results.append((expr, target))

    return results


# =====================================================================
# 第五节：搜索编排与结果筛选
# =====================================================================

def search_all_strategies(target):
    """
    运行所有搜索策略，返回去重后的表达式列表。
    每个元素为 (expr_str, computed_value)。
    """
    all_exprs = []
    seen = set()

    def add_results(results, strategy_name):
        for expr, val in results:
            normalized = expr.replace(" ", "")
            if normalized not in seen and abs(val) == abs(target):
                seen.add(normalized)
                all_exprs.append((expr, val, strategy_name))

    # 小数字先试直接分解
    if target <= 100000:
        add_results(strategy_A_direct_sum(target), "A")

    # 各种乘法策略
    add_results(strategy_B_114514_mul(target), "B")
    add_results(strategy_C_1145140_mul(target), "C")
    add_results(strategy_D_514_114_mix(target), "D")
    add_results(strategy_E_14514_mul(target), "E")
    add_results(strategy_F_division(target), "F")
    add_results(strategy_G_114514_base(target), "G")

    # 如果前面结果太少，对大数再用 A 补充
    if len(all_exprs) < 3 and target > 100000:
        add_results(strategy_A_direct_sum(target), "A")

    return all_exprs


def rate_expression(expr_str):
    """
    评分函数，按 function.md 第 6 节规则。
    返回 (level, emoji, label, raw_score)
    """
    score = 0

    # 114 出现次数 (+2 each, max +6)
    c114 = count_standalone(expr_str, 114)
    score += min(c114 * 2, 6)

    # 514 出现次数 (+3 each, max +9)
    c514 = count_standalone(expr_str, 514)
    score += min(c514 * 3, 9)

    # 114514 完整出现 (+5 each, max +10)
    c114514 = count_standalone(expr_str, 114514)
    score += min(c114514 * 5, 10)

    # 运算复杂度
    has_power = '²' in expr_str or '³' in expr_str or '^' in expr_str
    has_fact = '!' in expr_str or '阶乘' in expr_str
    score += 3 if (has_power or has_fact) else 1

    # 表达式长度（超过 5 个运算符 → +1）
    ops = sum(1 for c in expr_str if c in '×÷＋−')
    if ops > 5:
        score += 1

    # 恶臭数占比
    numbers = re.findall(r'\d+', expr_str)
    stench_set = set(ALL_POOL_MEGA)
    nums_int = [int(n) for n in numbers]
    if nums_int:
        ratio = sum(1 for n in nums_int if n in stench_set) / len(nums_int)
        if ratio > 0.7:
            score += 2

    # 等级转换
    if score <= 2:
        level = max(1, score)
        emoji = "🫵"
        label = "不够臭啊"
    elif score <= 5:
        level = max(3, score - 1)
        emoji = "💨"
        label = "微微发臭"
    elif score <= 8:
        level = score - 1
        emoji = "🤢"
        label = "有点味道了"
    elif score <= 12:
        level = score - 4
        emoji = "💩"
        label = "恶臭来袭"
    elif score <= 16:
        level = 9
        emoji = "🔥"
        label = "非常恶臭"
    else:
        level = 10
        emoji = "🏆"
        label = "究极恶臭！"

    return level, emoji, label, score


def select_top_expressions(all_exprs, count=5):
    """
    按恶臭等级排序，去重后选择前 count 个。
    优先保留不同类型的最佳组合。
    """
    if not all_exprs:
        return []

    # 计算每个表达式的评分
    scored = []
    for expr, val, strategy in all_exprs:
        level, emoji, label, score = rate_expression(expr)
        # 检查除数不为 0
        if '÷ 0' in expr:
            continue
        scored.append((expr, val, strategy, level, emoji, label, score))

    # 排序：先按等级降序，再按评分降序，再按长度（短的好）
    scored.sort(key=lambda x: (-x[3], -x[6], len(x[0])))

    # 去重（内容相似的去重）
    deduped = []
    seen_patterns = set()
    for item in scored:
        # 提取数字序列作为指纹
        nums = re.findall(r'\d+', item[0])
        fingerprint = tuple(sorted(int(n) for n in nums))
        if fingerprint not in seen_patterns:
            seen_patterns.add(fingerprint)
            deduped.append(item)

    return deduped[:count]


# =====================================================================
# 第六节：主流程
# =====================================================================

def generate(target):
    """
    主入口：对目标数字执行恶臭拆解，返回格式化的输出行列表。
    """
    results_lines = []

