ALL_POOL_MEGA = sorted(set(ALL_POOL + MEGA_POOL))

# 不含 0 数码位的纯池
CLEAN_POOL = sorted(ALL_POOL)

# =====================================================================
# 第二节：辅助函数
# =====================================================================

def has_digit_zero(n):
    """数字的十进制表示中是否含有 0 数码位"""
    return '0' in str(abs(n))

def eval_expr(expr_str):
    """安全计算表达式值（替换 Unicode 数学符号为 ASCII）"""
    s = expr_str.replace('×', '*').replace('−', '-').replace('÷', '/')
    s = s.replace('＋', '+')
    return eval(s)

def verify_no_zero_value(expr_str):
    """验证表达式计算不产生零值"""
    # 先快速检查是否有 a − a 模式
    if re.search(r'(?<!\d)(\d+)\s*−\s*\1(?!\d)', expr_str):
        return False
    try:
        return eval_expr(expr_str) != 0
    except:
        return False

def count_standalone(expr_str, target_num):
    """统计表达式中独立出现 target_num 的次数（非数字前缀）"""
    pattern = r'(?<!\d)' + str(target_num) + r'(?!\d)'
    return len(re.findall(pattern, expr_str))

def simplify_terms(terms):
    """合并正负抵消的同类项，简化表达式"""
    net = {}
    for sign, num in terms:
        net[num] = net.get(num, 0) + (1 if sign == '+' else -1)
    result = []
    for num, count in sorted(net.items(), reverse=True):
        if count > 0:
            result.extend([('+', num)] * count)
        elif count < 0:
            result.extend([('-', num)] * abs(count))
    return result

def terms_to_expr(terms):
    """将 [(sign, num), ...] 转为表达式字符串"""
    if not terms:
        return ""
    parts = []
    for i, (sign, num) in enumerate(terms):
        if i == 0:
            parts.append(f"{'' if sign == '+' else '−'}{num}")
        else:
            parts.append(f" {'+' if sign == '+' else '−'} {num}")
    return "".join(parts)

def term_sum(terms):
    """计算 terms 代数和"""
    return sum(v if s == '+' else -v for s, v in terms)

def format_expr_as_result(expr_str, target):
    """格式化为 N = expr 形式"""
    return f"{target} = {expr_str}"

# =====================================================================
# 第三节：核心分解算法（带缓存的 DP + DFS）
# =====================================================================

@lru_cache(maxsize=10000)
def decompose_sum(target, max_terms=8, pool=None):
    """
    DP/DFS：将 target 分解为 pool 中正数的和。
    返回 [n1, n2, ...] 列表，所有项为正，和为 target。
    返回 None 表示无解。
    """
    if pool is None:
        pool_tuple = tuple(ALL_POOL)
    else:
        pool_tuple = tuple(sorted(pool))

    target = abs(target)
    if target == 0:
        return []
    if target in pool_tuple:
        return [target]
    if max_terms <= 1:
        return None

    best = None
    for n in reversed(pool_tuple):
        if n > target or n == 0:
            continue
        rest = decompose_sum(target - n, max_terms - 1, pool_tuple)
        if rest is not None:
            cand = [n] + rest
            if best is None or len(cand) < len(best):
                best = cand
            if len(cand) <= 2:
                return cand
    return best


@lru_cache(maxsize=10000)
def decompose_mixed(target, max_terms=6, pool=None):
    """
    DP/DFS：将 target 分解为 pool 中带符号数的代数和。
    返回 [(sign, num), ...]，最终代数和 = target。
    不允许出现相同值相消（会得到 0）。
    返回 None 表示无解。
    """
    if pool is None:
        pool_tuple = tuple(ALL_POOL)
    else:
        pool_tuple = tuple(sorted(pool))

    target = int(target)
    if target == 0:
        return []

    # 直接命中
    if target in pool_tuple:
        return [('+', target)]
    if -target in pool_tuple:
        return [('-', target)]

    if max_terms <= 1:
        return None

    best = None

    for n in reversed(pool_tuple):
        if n == 0:
            continue

        # ---- 分支 1：n + rest = target => rest = target - n ----
        remaining = target - n
        if remaining != 0:
            rest = decompose_mixed(remaining, max_terms - 1, pool_tuple)
            if rest is not None:
                cand = [('+', n)] + rest
                # 检查是否产生零（无 a − a 模式）
                if not has_self_cancel(cand):
                    if best is None or len(cand) < len(best):
                        best = cand
                    if len(cand) <= 2:
                        return cand

        # ---- 分支 2：n - rest = target => rest = n - target ----
        if n > target:
            remaining2 = n - target
            if remaining2 != 0:
                rest2 = decompose_mixed(remaining2, max_terms - 1, pool_tuple)
                if rest2 is not None:
                    cand2 = [('+', n)]
                    for s, v in rest2:
                        # 翻转符号：如果 rest2 是 +v，那么 n - (+v) → 这里变成 −v
                        cand2.append(('-' if s == '+' else '+', v))
                    if not has_self_cancel(cand2):
                        if best is None or len(cand2) < len(best):
                            best = cand2
                        if len(cand2) <= 2:
                            return cand2

