def has_self_cancel(terms):
    """检查是否有 a − a 模式（会产生 0）"""
    net = {}
    for sign, num in terms:
        key = (sign, num)
        net[key] = net.get(key, 0) + 1
    for (s1, v1), c1 in net.items():
        if v1 == 0:
            return True
        # 检查是否存在相反的符号配对
        opposite_sign = '-' if s1 == '+' else '+'
        c2 = net.get((opposite_sign, v1), 0)
        if c1 > 0 and c2 > 0:
            # 有 +v 和 -v 同时存在 → 会互相抵消
            return True
    return False


def decompose_multiplicative(target, pool=None):
    """
    寻找 target = a × b + r 形式，其中 a, b 来自 pool。
    返回 (a, b, r, expr_format) 或 None。
    """
    if pool is None:
        p = ALL_POOL
    else:
        p = sorted(pool)

    candidates = []
    for a in reversed(p):
