def strategy_B_114514_mul(target):
    """
    【策略 B】114514 × k + r
    优先使用 114514 作为乘法基数
    """
    if target <= 114514:
        return []

    results = []
    base = 114514
    k = target // base
    r = target % base

    # B1: 直接 k 和 r
    k_str = str(k)
    r_str = f" + {r}" if r > 0 else ""
