    # B3: 分解 k（带符号混合）
    k_mixed = decompose_mixed(k, max_terms=4)
    if k_mixed:
        k_expr = terms_to_expr(k_mixed)
        r_part = f" + {r}" if r > 0 else ""
        expr = f"114514 × ({k_expr}){r_part}"
        if verify_no_zero_value(expr):
