    if r > 0:
        r_decomp = decompose_mixed(r, max_terms=5)
        if r_decomp:
            r_expr = terms_to_expr(r_decomp)
            expr = f"1145140 × {k} + {r_expr}"
            if verify_no_zero_value(expr):
