            r_expr2 = terms_to_expr(r_decomp2)
            expr = f"1145140 × ({k_expr2}) + {r_expr2}"
            if verify_no_zero_value(expr):
                results.append((expr, target))

    return results


def strategy_D_514_114_mix(target):
    """
    【策略 D】514 × a + 114 × b + r
    双臭混合，最大化 114/514 出现频率
    """
    results = []

    # D1: 贪婪找系数
    for a in range(1, min(target // 514 + 1, 50)):
        rem_after_514 = target - 514 * a
        if rem_after_514 < 0:
            break
        for b in range(0, min(rem_after_514 // 114 + 1, 50)):
            r = rem_after_514 - 114 * b
            if r == 0:
                expr = f"514 × {a} + 114 × {b}"
                if verify_no_zero_value(expr):
                    results.append((expr, target))
            elif r > 0 and r < 5000:
                r_decomp = decompose_mixed(r, max_terms=4)
                if r_decomp:
                    r_expr = terms_to_expr(r_decomp)
                    expr = f"514 × {a} + 114 × {b} + {r_expr}"
                    if verify_no_zero_value(expr):
                        results.append((expr, target))

            # 如果 a 或 b 本身可分解，更臭
            if a <= 200 and b <= 200:
                a_decomp = decompose_mixed(a, max_terms=3)
                b_decomp = decompose_mixed(b, max_terms=3)
                if a_decomp and b_decomp:
                    a_expr = terms_to_expr(a_decomp)
                    b_expr = terms_to_expr(b_decomp)
                    r2 = target - 514 * a - 114 * b
                    if r2 == 0:
                        expr = f"514 × ({a_expr}) + 114 × ({b_expr})"
                        if verify_no_zero_value(expr):
                            results.append((expr, target))
                    elif r2 > 0:
                        r_decomp2 = decompose_mixed(r2, max_terms=3)
                        if r_decomp2:
                            r_expr2 = terms_to_expr(r_decomp2)
                            expr = f"514 × ({a_expr}) + 114 × ({b_expr}) + {r_expr2}"
                            if verify_no_zero_value(expr):
                                results.append((expr, target))

    # D2: 反过来 114 × b - 514 × a
    for b in range(1, min(target // 114 + 1, 50)):
        val = 114 * b
        if val > target:
            diff = val - target
            r_decomp = decompose_mixed(diff, max_terms=4)
            if r_decomp:
                r_expr = terms_to_expr(r_decomp)
                expr = f"114 × {b} − ({r_expr})"
                full_expr = f"114 × {b} − {r_expr}"
                if verify_no_zero_value(full_expr):
                    results.append((full_expr, target))

    return results


def strategy_E_14514_mul(target):
    """
    【策略 E】14514 × k + r（近亲乘法变体）
    """
    if target <= 14514:
        return []

    results = []
    base = 14514
    k = target // base
    r = target % base

    # E1
    r_str = f" + {r}" if r > 0 else ""
    expr = f"14514 × {k}{r_str}"
    if verify_no_zero_value(expr):
        results.append((expr, target))

    # E2: 分解 k
    k_decomp = decompose_mixed(k, max_terms=4)
    if k_decomp:
        k_expr = terms_to_expr(k_decomp)
        r_part = f" + {r}" if r > 0 else ""
        expr = f"14514 × ({k_expr}){r_part}"
        if verify_no_zero_value(expr):
            results.append((expr, target))

    return results


def strategy_F_division(target):
    """
    【策略 F】除法还原：(a × b) ÷ c ± r
    利用 114514 × k 能被某个 pool 数整除来构造
    """
    results = []
    for a in [114514, 14514, 1145, 514, 114]:
        if a > target:
            continue
        # 尝试 N = (a × b) / d
        for d in BASE_POOL + [114, 514]:
            if d == 0:
                continue
            # 找 b 使得 a × b 接近 target × d
            approx = target * d // a
            for b in range(max(1, approx - 5), approx + 6):
                prod = a * b
                if prod % d != 0:
                    continue
                val = prod // d
                r = target - val
                if r == 0:
                    expr = f"({a} × {b}) ÷ {d}"
                    if verify_no_zero_value(expr):
                        results.append((expr, target))
                elif abs(r) < 10000:
                    r_decomp = decompose_mixed(abs(r), max_terms=3)
                    if r_decomp:
                        r_expr = terms_to_expr(r_decomp)
                        sign = '+'
                        if r < 0:
                            sign = '−'
                            r_expr = terms_to_expr([('+' if s == '-' else '-', v) for s, v in r_decomp])
                        expr = f"({a} × {b}) ÷ {d} {sign} {r_expr}"
                        if verify_no_zero_value(expr):
                            results.append((expr, target))

    return results


def strategy_G_114514_base(target):
    """
    【策略 G】114514 进制展开（学院派）
    将 target 以 114514 为基展开，每位用 pool 数字表示
    """
    if target < 114514:
        return []

    results = []
    base = 114514

    # 计算进制表示
    n = target
    digits = []
    while n > 0:
        digits.append(n % base)
        n //= base

    # 构建表达式
    parts = []
    valid = True
    for i, d in enumerate(digits):
        if d == 0:
            valid = False
            break
        if d in ALL_POOL:
            if i == 0:
                parts.append(str(d))
            elif i == 1:
                parts.append(f"{d} × 114514")
            else:
                parts.append(f"{d} × 114514^{i}")
        else:
            # 尝试分解 d
            d_decomp = decompose_sum(d, max_terms=3)
            if d_decomp:
                d_expr = " + ".join(str(n) for n in d_decomp)
                if i == 0:
                    parts.append(f"({d_expr})")
                elif i == 1:
                    parts.append(f"({d_expr}) × 114514")
                else:
                    parts.append(f"({d_expr}) × 114514^{i}")
            else:
                valid = False
                break

    if valid and parts:
        expr = " + ".join(reversed(parts))
        if verify_no_zero_value(expr):
            results.append((expr, target))

    return results


# =====================================================================
# 第五节：搜索编排与结果筛选
# =====================================================================

def search_all_strategies(target):
    """
    运行所有搜索策略，返回去重后的表达式列表。
    每个元素为 (expr_str, computed_value)。
    """
    all_exprs = []
    seen = set()

    def add_results(results, strategy_name):
        for expr, val in results:
            normalized = expr.replace(" ", "")
            if normalized not in seen and abs(val) == abs(target):
                seen.add(normalized)
                all_exprs.append((expr, val, strategy_name))

    # 小数字先试直接分解
    if target <= 100000:
        add_results(strategy_A_direct_sum(target), "A")

    # 各种乘法策略
    add_results(strategy_B_114514_mul(target), "B")
    add_results(strategy_C_1145140_mul(target), "C")
    add_results(strategy_D_514_114_mix(target), "D")
    add_results(strategy_E_14514_mul(target), "E")
    add_results(strategy_F_division(target), "F")
    add_results(strategy_G_114514_base(target), "G")

    # 如果前面结果太少，对大数再用 A 补充
    if len(all_exprs) < 3 and target > 100000:
        add_results(strategy_A_direct_sum(target), "A")

    return all_exprs


def rate_expression(expr_str):
    """
    评分函数，按 function.md 第 6 节规则。
    返回 (level, emoji, label, raw_score)
    """
    score = 0

    # 114 出现次数 (+2 each, max +6)
    c114 = count_standalone(expr_str, 114)
    score += min(c114 * 2, 6)

    # 514 出现次数 (+3 each, max +9)
    c514 = count_standalone(expr_str, 514)
    score += min(c514 * 3, 9)

    # 114514 完整出现 (+5 each, max +10)
    c114514 = count_standalone(expr_str, 114514)
    score += min(c114514 * 5, 10)

    # 运算复杂度
    has_power = '²' in expr_str or '³' in expr_str or '^' in expr_str
    has_fact = '!' in expr_str or '阶乘' in expr_str
    score += 3 if (has_power or has_fact) else 1

    # 表达式长度（超过 5 个运算符 → +1）
    ops = sum(1 for c in expr_str if c in '×÷＋−')
    if ops > 5:
        score += 1

    # 恶臭数占比
    numbers = re.findall(r'\d+', expr_str)
    stench_set = set(ALL_POOL_MEGA)
    nums_int = [int(n) for n in numbers]
    if nums_int:
        ratio = sum(1 for n in nums_int if n in stench_set) / len(nums_int)
        if ratio > 0.7:
            score += 2

    # 等级转换
    if score <= 2:
        level = max(1, score)
        emoji = "🫵"
        label = "不够臭啊"
    elif score <= 5:
        level = max(3, score - 1)
        emoji = "💨"
        label = "微微发臭"
    elif score <= 8:
        level = score - 1
        emoji = "🤢"
        label = "有点味道了"
    elif score <= 12:
        level = score - 4
        emoji = "💩"
        label = "恶臭来袭"
    elif score <= 16:
        level = 9
        emoji = "🔥"
        label = "非常恶臭"
    else:
        level = 10
        emoji = "🏆"
        label = "究极恶臭！"

    return level, emoji, label, score


def select_top_expressions(all_exprs, count=5):
    """
    按恶臭等级排序，去重后选择前 count 个。
    优先保留不同类型的最佳组合。
    """
    if not all_exprs:
        return []

    # 计算每个表达式的评分
    scored = []
    for expr, val, strategy in all_exprs:
        level, emoji, label, score = rate_expression(expr)
        # 检查除数不为 0
        if '÷ 0' in expr:
            continue
        scored.append((expr, val, strategy, level, emoji, label, score))

    # 排序：先按等级降序，再按评分降序，再按长度（短的好）
    scored.sort(key=lambda x: (-x[3], -x[6], len(x[0])))

    # 去重（内容相似的去重）
    deduped = []
    seen_patterns = set()
    for item in scored:
        # 提取数字序列作为指纹
        nums = re.findall(r'\d+', item[0])
        fingerprint = tuple(sorted(int(n) for n in nums))
        if fingerprint not in seen_patterns:
            seen_patterns.add(fingerprint)
            deduped.append(item)

    return deduped[:count]


# =====================================================================
# 第六节：主流程
# =====================================================================

def generate(target):
    """
    主入口：对目标数字执行恶臭拆解，返回格式化的输出行列表。
    """
    results_lines = []

    # 特殊处理：本身就是 114514
    if target == 114514:
        results_lines.append(f"数字 114514 的恶臭拆解：")
        results_lines.append("")
        results_lines.append("🤢 完美！114514 本身就是最臭的数字！")
        results_lines.append("恶臭等级：10/10 🏆 究极恶臭！")
        results_lines.append("")
        results_lines.append("💩 其他恶臭组合：")
        results_lines.append("114514 = 114000 + 514")
        results_lines.append("114514 = 114 × 1000 + 514")
        results_lines.append("114514 = 514 × 222 + 114 + 114 − 5 + 1 − 1 + 4")
        results_lines.append("")
        results_lines.append("🫵 你就是传说中的人？！")
        return results_lines

    # 运行所有搜索策略
    exprs = search_all_strategies(target)

    if not exprs:
        # 实在找不到，输出经典学院派
        return generate_academic(target)

    top5 = select_top_expressions(exprs, 5)

    if not top5:
        return generate_academic(target)

    results_lines.append(f"🤢 数字 {target} 的恶臭拆解：")
    results_lines.append("")

    # 最佳恶臭
    best = top5[0]
    best_expr, _, _, best_level, best_emoji, best_label, _ = best
    results_lines.append("📿 最佳恶臭：")
    results_lines.append(f"{target} = {best_expr}")
    results_lines.append(f"恶臭等级：{best_level}/10 {best_emoji} {best_label}")
    results_lines.append("")

    # 其他恶臭组合
    if len(top5) > 1:
        results_lines.append("💩 其他恶臭组合：")
        for item in top5[1:]:
            expr, _, _, _, _, _, _ = item
            results_lines.append(f"{target} = {expr}")
        results_lines.append("")

    results_lines.append("--- ")
    results_lines.append("🫵 你也是恶臭人了！")

    return results_lines


def generate_academic(target):
    """
    学院派兜底：当通用搜索找不到足够好的结果时使用。
    """
    results_lines = []
    results_lines.append(f"🤢 数字 {target} 的恶臭拆解（学院派）：")
    results_lines.append("")

    # 使用 114514 进制展开
    base = 114514
    n = target
    parts = []
    i = 0
    while n > 0:
        d = n % base
        if d != 0:
            if i == 0:
                parts.append(f"{d}")
            elif i == 1:
                parts.append(f"{d} × 114514")
            else:
                parts.append(f"{d} × 114514^{i}")
        n //= base
        i += 1

    if parts:
        expr = " + ".join(reversed(parts))
        level, emoji, label, score = rate_expression(expr)
        results_lines.append("📿 最佳恶臭（学院派）：")
        results_lines.append(f"{target} = {expr}")
        results_lines.append(f"恶臭等级：{level}/10 {emoji} {label}")
        results_lines.append("")
    else:
        # 最后兜底：114514 × k + r
        k = target // 114514
        r = target % 114514
        expr2 = f"114514 × {k} + {r}"
        level2, emoji2, label2, _ = rate_expression(expr2)
        results_lines.append("📿 最佳恶臭（学院派）：")
        results_lines.append(f"{target} = {expr2}")
        results_lines.append(f"恶臭等级：{level2}/10 {emoji2} {label2}")
        results_lines.append("")

    # 额外尝试 514 分解
    k514 = target // 514
    r514 = target % 514
    expr3 = f"514 × {k514} + {r514}"
    l3, e3, lb3, _ = rate_expression(expr3)
    results_lines.append("💩 其他恶臭组合：")
    results_lines.append(f"{target} = {expr3}")

    # 114 分解
    k114 = target // 114
    r114 = target % 114
    expr4 = f"114 × {k114} + {r114}"
    results_lines.append(f"{target} = {expr4}")
    results_lines.append("")

    results_lines.append("--- ")
    results_lines.append("🫵 你也是恶臭人了！")

    return results_lines


def main():
    if len(sys.argv) < 2:
        print("用法: python3 generate.py <数字>")
        print("示例: python3 generate.py 20070521")
        sys.exit(1)

    try:
        target = int(sys.argv[1])
    except ValueError:
        print("❌ 请输入有效的正整数")
        sys.exit(1)

    if target <= 0:
        print("🤢 请输入正整数。0 和负数不能进行恶臭拆解。")
        sys.exit(1)

    if target > 10**9:
        print("🤢 数字太大了，暂时只支持 10 亿以内的数字")
        print("试试小一点的数字吧！")
        sys.exit(1)

    lines = generate(target)
    for line in lines:
        print(line)


if __name__ == "__main__":
    main()
"}

