#!/usr/bin/env python3
"""
数字恶臭化生成器 — 通用搜索版 (v3)
====================================
使用 114514 系列数字池，通过通用 DFS/DP 搜索算法，
自动拆解任意目标数字为恶臭风格数学表达式。

约束：不产生值为 0 的中间结果。表达式中的数字尽量不含 0 数码位。
运算符只用 + − × ÷，不出现 −− 双负号。

搜索策略：
  A - 直接加法分解（纯正数之和）
  B - 114514 × k + r（基础乘法拆解，k 和 r 都分解）
  C - 1145140 × k + r（大数乘法拆解）
  D - 514 × a + 114 × b + r（双臭混合）
  E - 14514 × k + r（近亲乘法变体）
  F - 除法还原：(a × b) ÷ c + r 
  G - 114514 进制展开（学院派）

用法：
    python3 generate.py <数字>
    python3 generate.py 20070521

灵感源自 lab.magiconch.com 的数字恶臭化工具。
"""

import sys
import re
import math
from functools import lru_cache

# =====================================================================
# 第一节：恶臭数字池
# =====================================================================

# 基础数集（不含 0 数码位）
BASE_POOL = [1, 4, 5, 11, 14, 15, 51, 54]
# 扩展数集（不含 0 数码位）
EXT_POOL = [114, 514, 1145, 1451, 14514, 114514]
# 巨型数（含 0 数码位的超级数，用于大数场景）
MEGA_POOL = [1145140, 1919810, 1145141919810]

# 全量池
ALL_POOL = sorted(set(BASE_POOL + EXT_POOL))
ALL_POOL_MEGA = sorted(set(ALL_POOL + MEGA_POOL))

# =====================================================================
# 第二节：辅助函数
# =====================================================================

def has_digit_zero(n):
    """数字的十进制表示中是否含有 0 数码位"""
    return '0' in str(abs(n))

def eval_expr(expr_str):
    """安全计算表达式值（替换 Unicode 数学符号为 ASCII）"""
    s = expr_str.replace('×', '*').replace('−', '-').replace('÷', '/')
    s = s.replace('＋', '+')
    return eval(s)

def verify_no_zero_value(expr_str):
    """验证表达式计算不产生零值"""
    if re.search(r'(?<!\d)(\d+)\s*−\s*\1(?!\d)', expr_str):
        return False
    if '÷ 0' in expr_str or '÷0' in expr_str:
        return False
    try:
        return eval_expr(expr_str) != 0
    except:
        return False

def count_standalone(expr_str, target_num):
    """统计表达式中独立出现 target_num 的次数（非数字前缀）"""
    pattern = r'(?<!\d)' + str(target_num) + r'(?!\d)'
    return len(re.findall(pattern, expr_str))

def terms_sum(terms):
    """计算 [(sign, num), ...] 的代数和"""
    return sum(v if s == '+' else -v for s, v in terms)

def has_any_zero_term(terms):
    """检查是否有值为 0 的项或 a − a 抵消"""
    for s, v in terms:
        if v == 0:
            return True
    net = {}
    for s, v in terms:
        net[v] = net.get(v, 0) + (1 if s == '+' else -1)
    return any(c == 0 for c in net.values())

def terms_to_expr(terms):
    """将 [(sign, num), ...] 转为表达式字符串，连接处无双负号"""
    if not terms:
        return ""
    parts = []
    for i, (sign, num) in enumerate(terms):
        if i == 0:
            if sign == '+':
                parts.append(str(num))
            else:
                parts.append(f"−{num}")
        else:
            # 如果上一个是 − 结果，这里再 − 就会成 −−，转为 + 来避免
            prev_end = parts[-1][-1] if parts else ''
            if sign == '+':
                parts.append(f" + {num}")
            else:
                # 前面已经是负号结尾或数字结尾都没问题
                parts.append(f" − {num}")
    return "".join(parts)

def expr_has_bad_patterns(expr_str):
    """检查表达式是否包含不应出现的模式"""
    # ÷ 1
    if re.search(r'÷\s*1(?!\d)', expr_str):
        return True
    # × 1
    if re.search(r'×\s*1(?!\d)', expr_str):
        return True
    # ÷ 0
    if re.search(r'÷\s*0', expr_str):
        return True
    # − − (double minus)
    if '− −' in expr_str or '−−' in expr_str:
        return True
    # 数字中含 0 数码位
    nums = re.findall(r'\d+', expr_str)
    for n in nums:
        if '0' in n:
            return True
    return False

# =====================================================================
# 第三节：核心分解算法（带缓存的 DP + DFS）
# =====================================================================

@lru_cache(maxsize=10000)
def decompose_sum(target, max_terms=8, pool=None):
    """
    DP/DFS：将 target 分解为 pool 中正数的加法链。
    返回 [n1, n2, ...] 列表，和为 target。
    返回 None 表示无解。
    所有返回的数都不含 0 数码位（除非 pool 本身含 0）。
    """
    if pool is None:
        pool_tuple = tuple(ALL_POOL)
    else:
        pool_tuple = tuple(sorted(pool))

    target = abs(target)
    if target == 0:
        return []
    if target in pool_tuple:
        return [target]
    if max_terms <= 1:
        return None

    best = None
    for n in reversed(pool_tuple):
        if n > target or n == 0:
            continue
        rest = decompose_sum(target - n, max_terms - 1, pool_tuple)
        if rest is not None:
            cand = [n] + rest
            if best is None or len(cand) < len(best):
                best = cand
            if len(cand) <= 2:
                return cand
    return best


@lru_cache(maxsize=10000)
def decompose_mixed(target, max_terms=6, pool=None):
    """
    DP/DFS：将 target 分解为 pool 中带符号数的代数和。
    返回 [(sign, num), ...] 列表，代数和 = target。
    不允许出现相同值正负相消。
    返回 None 表示无解。
    """
    if pool is None:
        pool_tuple = tuple(ALL_POOL)
    else:
        pool_tuple = tuple(sorted(pool))

    target = int(target)
    if target == 0:
        return None  # 不允许结果为 0
    if target in pool_tuple:
        return [('+', target)]
    if -target in pool_tuple:
        return [('-', target)]

    if max_terms <= 1:
        return None

    best = None

    for n in reversed(pool_tuple):
        if n == 0:
            continue

        # 分支 1：n + rest = target → rest = target − n
        r1 = target - n
        if abs(r1) > 0:  # 不允许 0
            rest1 = decompose_mixed(r1, max_terms - 1, pool_tuple)
            if rest1 is not None:
                cand = [('+', n)] + rest1
                if not has_any_zero_term(cand):
                    if best is None or len(cand) < len(best):
                        best = cand
                    if len(cand) <= 2:
                        return cand

        # 分支 2：−n + rest = target → rest = target + n
        r2 = target + n
        if abs(r2) > 0:
            rest2 = decompose_mixed(r2, max_terms - 1, pool_tuple)
            if rest2 is not None:
                cand = [('-', n)] + rest2
                if not has_any_zero_term(cand):
                    if best is None or len(cand) < len(best):
                        best = cand

        # 分支 3：n − rest = target → rest = n − target
        if n > target:
            r3 = n - target
            if r3 > 0:
                rest3 = decompose_mixed(r3, max_terms - 1, pool_tuple)
                if rest3 is not None:
                    cand = [('+', n)]
                    for s, v in rest3:
                        cand.append(('-' if s == '+' else '+', v))
                    if not has_any_zero_term(cand):
                        if best is None or len(cand) < len(best):
                            best = cand

        # 分支 4：target = −n + rest, where n > target (n is bigger)
        # Actually this is same as branch 2

    return best


def decompose_simple_sum(target, max_terms=8):
    """纯正数加法分解，适合用在括号内部。确保不含 0 数码位。"""
    result = decompose_sum(target, max_terms)
    if result is None:
        return None
    # 验证不含 0 数码位
    for n in result:
        if has_digit_zero(n):
            return None
    return result


def sum_decomp_to_expr(terms):
    """将 [n1, n2, ...] 格式化为加法连接"""
    if not terms:
        return ""
    return " + ".join(str(n) for n in terms)


