def strategy_A_direct_sum(target):
    """策略 A：直接加减拆解（纯加法链）"""
    results = []

    # 如果 target 本身就在池中
    if target in (ALL_POOL + MEGA_POOL):
        results.append((str(target), target, "A0"))
        return results

    # A1: 纯加法分解
    s_decomp = decompose_simple_sum(target, max_terms=8)
    if s_decomp:
        expr = sum_decomp_to_expr(s_decomp)
        if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
            results.append((expr, target, "A1"))

    # A2: 用 114 或 514 锚定的加法组合
    for anchor in [114, 514, 1145, 1451]:
        if anchor >= target:
            continue
        rest = target - anchor
        s_rest = decompose_simple_sum(rest, max_terms=6)
        if s_rest:
            expr = f"{anchor} + {sum_decomp_to_expr(s_rest)}"
            if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
                results.append((expr, target, "A2"))

    # A3: 两个锚点
    anchors_to_try = [(114, 514), (114, 1145), (514, 1145), (514, 1451), (114, 1451)]
    for a1, a2 in anchors_to_try:
        if a1 + a2 >= target:
            continue
        rest3 = target - a1 - a2
        s3 = decompose_simple_sum(rest3, max_terms=5)
        if s3:
            expr = f"{a1} + {a2} + {sum_decomp_to_expr(s3)}"
            if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
                results.append((expr, target, "A3"))

    return results


def strategy_B_114514_mul(target):
    """策略 B：114514 × k + r（基础乘法拆解）"""
    if target <= 114514:
        return []

    results = []
    base = 114514
    k = target // base
    r = target % base

    # ---------- B1: 直接表达 ----------
    if r == 0:
        expr = f"114514 × {k}"
        if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
            results.append((expr, target, "B1"))
    else:
        expr = f"114514 × {k} + {r}"
        if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
            results.append((expr, target, "B1"))

    # ---------- B2: 分解 k（正数加法链）放在括号内 ----------
    k_decomp = decompose_simple_sum(k, max_terms=5)
    if k_decomp:
        k_expr = sum_decomp_to_expr(k_decomp)
        if r == 0:
            expr = f"114514 × ({k_expr})"
        else:
            expr = f"114514 × ({k_expr}) + {r}"
        if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
            results.append((expr, target, "B2"))

    # ---------- B3: 分解 r ----------
    if r > 0 and r < base:
        r_decomp = decompose_simple_sum(r, max_terms=5)
        if r_decomp:
            r_expr = sum_decomp_to_expr(r_decomp)
            expr = f"114514 × {k} + {r_expr}"
            if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
                results.append((expr, target, "B3"))

        # B4: k 和 r 都分解
        kd4 = decompose_simple_sum(k, max_terms=4)
        rd4 = decompose_simple_sum(r, max_terms=4)
        if kd4 and rd4:
            expr = f"114514 × ({sum_decomp_to_expr(kd4)}) + {sum_decomp_to_expr(rd4)}"
            if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
                results.append((expr, target, "B4"))

    # ---------- B5: k−1 和 r+base（获得另一种分解）----------
    if k > 1:
        k2 = k - 1
        r2 = r + base
        kd5 = decompose_simple_sum(k2, max_terms=4)
        rd5 = decompose_simple_sum(r2, max_terms=5)
        if kd5 and rd5:
            k_expr5 = sum_decomp_to_expr(kd5)
            r_expr5 = sum_decomp_to_expr(rd5)
            expr = f"114514 × ({k_expr5}) + {r_expr5}"
            if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
                results.append((expr, target, "B5"))

        # B6: 只用 k−1，r 写为 r+base（直接用数字）
        expr6 = f"114514 × {k2} + {r2}"
        if verify_no_zero_value(expr6) and not expr_has_bad_patterns(expr6):
            results.append((expr6, target, "B6"))

    return results


def strategy_C_1145140_mul(target):
    """策略 C：1145140 × k + r（大数乘法拆解）"""
    if target <= 1145140:
        return []

    results = []
    base = 1145140
    k = target // base
    r = target % base

    # C1: 直接
    if r == 0:
        expr = f"1145140 × {k}"
    else:
        expr = f"1145140 × {k} + {r}"
    if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
        results.append((expr, target, "C1"))

    # C2: 分解 k
    kd = decompose_simple_sum(k, max_terms=4)
    if kd:
        if r == 0:
            expr = f"1145140 × ({sum_decomp_to_expr(kd)})"
        else:
            expr = f"1145140 × ({sum_decomp_to_expr(kd)}) + {r}"
        if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
            results.append((expr, target, "C2"))

    # C3: 分解 r
    if r > 0 and r < base:
        rd = decompose_simple_sum(r, max_terms=5)
        kd3 = decompose_simple_sum(k, max_terms=3)
        if kd3 and rd:
            expr = f"1145140 × ({sum_decomp_to_expr(kd3)}) + {sum_decomp_to_expr(rd)}"
            if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
                results.append((expr, target, "C3"))

    return results


def strategy_D_514_114_mix(target):
    """策略 D：514 × a + 114 × b + r（双臭混合）"""
    results = []

    # 搜索 a, b 系数
    max_a = min(target // 514 + 1, 30)
    for a in range(1, max_a):
        after_514 = target - 514 * a
        if after_514 < 0:
            break
        max_b = min(after_514 // 114 + 1, 30)
        for b in range(0, max_b):
            r = after_514 - 114 * b
            if r < 0:
                continue
            if r > 5000:  # 余数太大就不算了
                continue

            if r == 0:
                expr = f"514 × {a} + 114 × {b}"
                if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
                    results.append((expr, target, "D1"))
            else:
                # 分解 r
                rd = decompose_simple_sum(r, max_terms=4)
                if rd:
                    r_expr = sum_decomp_to_expr(rd)

                    # 无括号版
                    expr_a = f"514 × {a} + 114 × {b} + {r_expr}"
                    if verify_no_zero_value(expr_a) and not expr_has_bad_patterns(expr_a):
                        results.append((expr_a, target, "D2a"))

            # 尝试分解 a 和 b 本身（放在括号内更臭）
            if a <= 200 and b <= 200:
                ad = decompose_simple_sum(a, max_terms=3)
                bd = decompose_simple_sum(b, max_terms=3)
                if ad and bd:
                    a_expr = sum_decomp_to_expr(ad)
                    b_expr = sum_decomp_to_expr(bd)
                    r2 = target - 514 * a - 114 * b
                    if r2 == 0:
                        expr = f"514 × ({a_expr}) + 114 × ({b_expr})"
                        if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
                            results.append((expr, target, "D3"))
                    elif r2 > 0:
                        rd3 = decompose_simple_sum(r2, max_terms=3)
                        if rd3:
                            expr = f"514 × ({a_expr}) + 114 × ({b_expr}) + {sum_decomp_to_expr(rd3)}"
                            if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
                                results.append((expr, target, "D3"))

    return results


def strategy_E_14514_mul(target):
    """策略 E：14514 × k + r（近亲乘法变体）"""
    if target <= 14514:
        return []

    results = []
    base = 14514
    k = target // base
    r = target % base

    # E1
    if r == 0:
        expr = f"14514 × {k}"
    else:
        expr = f"14514 × {k} + {r}"
    if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
