    # E2: 分解 k
    kd = decompose_simple_sum(k, max_terms=4)
    if kd:
        if r == 0:
            expr = f"14514 × ({sum_decomp_to_expr(kd)})"
        else:
            expr = f"14514 × ({sum_decomp_to_expr(kd)}) + {r}"
        if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
            results.append((expr, target, "E2"))

    # E3: 分解 r
    if r > 0:
        rd = decompose_simple_sum(r, max_terms=5)
