    return results


def strategy_F_division(target):
    """策略 F：(a × b) ÷ c + r（除法还原）"""
    results = []

    multipliers = [114514, 14514, 514, 114]
    divisors = [n for n in [5, 4, 11, 14, 15, 51, 54, 114, 514] if n != 1]

    for a in multipliers:
        if a > target * 10:
            continue
        for d in divisors:
            if d == 1 or d == 0:
                continue
            # find b such that (a * b) / d is close to target
            b_approx = target * d // a
            for b in range(max(1, b_approx - 3), b_approx + 4):
                prod = a * b
                if prod % d != 0:
                    continue
                val = prod // d
                if val == target:
                    expr = f"({a} × {b}) ÷ {d}"
                    if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
                        results.append((expr, target, "F"))
                elif abs(target - val) <= 2000:
                    r = target - val
                    if r > 0:
                        rd = decompose_simple_sum(r, max_terms=3)
                        if rd:
                            expr = f"({a} × {b}) ÷ {d} + {sum_decomp_to_expr(rd)}"
                            if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
                                results.append((expr, target, "F"))

    return results


def strategy_G_114514_base(target):
    """策略 G：114514 进制展开（学院派）"""
    if target < 114514:
        return []

    results = []
    base = 114514
    n = target
    digits = []
    while n > 0:
        d = n % base
        if d == 0:
            return []
        digits.append(d)
        n //= base

    parts = []
    ok = True
    for i, d in enumerate(digits):
        if has_digit_zero(d):
            ok = False
            break
        if i == 0:
            parts.append(str(d))
        elif i == 1:
            parts.append(f"{d} × 114514")
        else:
            parts.append(f"{d} × 114514^{i}")

    if ok and parts:
        expr = " + ".join(reversed(parts))
        if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
            results.append((expr, target, "G"))

    return results


