def search_all_strategies(target):
    """运行所有搜索策略，返回去重后的表达式列表"""
    all_exprs = []
    seen = set()

    def add_results(results):
        for expr, val, strat in results:
            norm = re.sub(r'\s+', '', expr)
            if norm not in seen:
                seen.add(norm)
                all_exprs.append((expr, val, strat))

    # 按顺序执行各策略
    add_results(strategy_A_direct_sum(target))
    add_results(strategy_B_114514_mul(target))
    add_results(strategy_D_514_114_mix(target))
    add_results(strategy_E_14514_mul(target))
    add_results(strategy_F_division(target))
    add_results(strategy_G_114514_base(target))

    # 大数补 C
    if target > 5000000:
        add_results(strategy_C_1145140_mul(target))

    return all_exprs


def rate_expression(expr_str):
    """
    评分函数，按 function.md 第 6 节规则。
    返回 (level, emoji, label, raw_score)
    """
    score = 0

    # 114 出现次数 (+2 each, max +6)
    c114 = count_standalone(expr_str, 114)
    score += min(c114 * 2, 6)

    # 514 出现次数 (+3 each, max +9)
    c514 = count_standalone(expr_str, 514)
    score += min(c514 * 3, 9)

    # 114514 完整出现 (+5 each, max +10)
    c114514 = count_standalone(expr_str, 114514)
    score += min(c114514 * 5, 10)

    # 运算复杂度
    has_power = '²' in expr_str or '³' in expr_str or '^' in expr_str
    score += 3 if has_power else 1

    # 表达式长度（超过 5 个运算符 → +1）
    ops = sum(1 for c in expr_str if c in '×÷＋−')
    if ops > 5:
        score += 1

    # 恶臭数占比
    numbers = re.findall(r'\d+', expr_str)
    stench_set = set(ALL_POOL_MEGA)
    nums_int = [int(n) for n in numbers]
    if nums_int:
        ratio = sum(1 for n in nums_int if n in stench_set) / len(nums_int)
        if ratio > 0.7:
            score += 2

    # 等级转换
    if score <= 2:
        level = max(1, score)
        emoji = "🫵"
        label = "不够臭啊"
    elif score <= 5:
        level = max(3, score - 1)
        emoji = "💨"
        label = "微微发臭"
    elif score <= 8:
        level = score - 1
        emoji = "🤢"
        label = "有点味道了"
    elif score <= 12:
        level = score - 4
        emoji = "💩"
        label = "恶臭来袭"
    elif score <= 16:
        level = 9
        emoji = "🔥"
        label = "非常恶臭"
    else:
        level = 10
        emoji = "🏆"
        label = "究极恶臭！"

    return level, emoji, label, score


def select_top_expressions(all_exprs, max_count=5):
    """按恶臭等级排序，去重后选择前 max_count 个"""
    if not all_exprs:
        return []

    scored = []
    seen_fingerprints = set()

    for expr, val, strategy in all_exprs:
        level, emoji, label, score = rate_expression(expr)

        # 指纹去重：排序后的数字列表
        nums = re.findall(r'\d+', expr)
        fingerprint = tuple(sorted(int(n) for n in nums))
        if fingerprint in seen_fingerprints:
            continue
        seen_fingerprints.add(fingerprint)

        scored.append((expr, val, strategy, level, emoji, label, score))

    # 排序：等级降序 → 评分降序 → 表达式短优先
    scored.sort(key=lambda x: (-x[3], -x[6], len(x[0])))
    return scored[:max_count]


