def generate_academic(target):
    """学院派兜底：当通用搜索找不到足够好的结果时使用"""
    results_lines = []
    results_lines.append(f"🤢 数字 {target} 的恶臭拆解（学院派）：")
    results_lines.append("")

    # 114514 进制展开
    base = 114514
    n = target
    parts = []
    i = 0
    ok = True
    while n > 0:
        d = n % base
        if d == 0:
            ok = False
            break
        if has_digit_zero(d):
            ok = False
            break
        if i == 0:
            parts.append(f"{d}")
        elif i == 1:
            parts.append(f"{d} × 114514")
        else:
            parts.append(f"{d} × 114514^{i}")
        n //= base
        i += 1

    if ok and parts:
        expr = " + ".join(reversed(parts))
        level, emoji, label, _ = rate_expression(expr)
        results_lines.append("📿 最佳恶臭（学院派）：")
        results_lines.append(f"{target} = {expr}")
        results_lines.append(f"恶臭等级：{level}/10 {emoji} {label}")
        results_lines.append("")
    else:
        k = target // 114514
        r = target % 114514
        expr2 = f"114514 × {k} + {r}"
        level2, emoji2, label2, _ = rate_expression(expr2)
        results_lines.append("📿 最佳恶臭（学院派）：")
        results_lines.append(f"{target} = {expr2}")
        results_lines.append(f"恶臭等级：{level2}/10 {emoji2} {label2}")
        results_lines.append("")

    # 附加
    k514 = target // 514
    r514 = target % 514
    expr3 = f"514 × {k514} + {r514}"
    if not expr_has_bad_patterns(expr3):
        results_lines.append("💩 其他恶臭组合：")
        results_lines.append(f"{target} = {expr3}")

        k114 = target // 114
        r114 = target % 114
        expr4 = f"114 × {k114} + {r114}"
        if not expr_has_bad_patterns(expr4):
            results_lines.append(f"{target} = {expr4}")
        results_lines.append("")

    results_lines.append("--- ")
    results_lines.append("🫵 你也是恶臭人了！")

    return results_lines


def main():
    if len(sys.argv) < 2:
        print("用法: python3 generate.py <数字>")
        print("示例: python3 generate.py 20070521")
        sys.exit(1)

    try:
        target = int(sys.argv[1])
    except ValueError:
        print("❌ 请输入有效的正整数")
        sys.exit(1)

    if target <= 0:
        print("🤢 请输入正整数。0 和负数不能进行恶臭拆解。")
        sys.exit(1)

    if target > 10**9:
        print("🤢 数字太大了，暂时只支持 10 亿以内的数字")
        print("试试小一点的数字吧！")
        sys.exit(1)

    lines = generate(target)
    for line in lines:
        print(line)


if __name__ == "__main__":
    main()

