def strategy_C_1145140_mul(target):
    """策略 C：1145140 × k + r（大数乘法拆解）"""
    if target <= 1145140:
        return []

    results = []
    base = 1145140
    k = target // base
    r = target % base

    # C1: 直接
    if r == 0:
        expr = f"1145140 × {k}"
    else:
        expr = f"1145140 × {k} + {r}"
    if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
        results.append((expr, target, "C1"))

    # C2: 分解 k
    kd = decompose_simple_sum(k, max_terms=4)
    if kd:
        if r == 0:
            expr = f"1145140 × ({sum_decomp_to_expr(kd)})"
        else:
            expr = f"1145140 × ({sum_decomp_to_expr(kd)}) + {r}"
        if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
            results.append((expr, target, "C2"))

    # C3: 分解 r
    if r > 0 and r < base:
        rd = decompose_simple_sum(r, max_terms=5)
        kd3 = decompose_simple_sum(k, max_terms=3)
        if kd3 and rd:
            expr = f"1145140 × ({sum_decomp_to_expr(kd3)}) + {sum_decomp_to_expr(rd)}"
            if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
                results.append((expr, target, "C3"))

    return results


def strategy_D_514_114_mix(target):
    """策略 D：514 × a + 114 × b + r（双臭混合）"""
    results = []

    # 搜索 a, b 系数
    max_a = min(target // 514 + 1, 30)
    for a in range(1, max_a):
        after_514 = target - 514 * a
        if after_514 < 0:
            break
        max_b = min(after_514 // 114 + 1, 30)
        for b in range(0, max_b):
            r = after_514 - 114 * b
            if r < 0:
                continue
            if r > 5000:  # 余数太大就不算了
                continue

            if r == 0:
                expr = f"514 × {a} + 114 × {b}"
                if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
                    results.append((expr, target, "D1"))
            else:
                # 分解 r
                rd = decompose_simple_sum(r, max_terms=4)
                if rd:
                    r_expr = sum_decomp_to_expr(rd)

                    # 无括号版
                    expr_a = f"514 × {a} + 114 × {b} + {r_expr}"
                    if verify_no_zero_value(expr_a) and not expr_has_bad_patterns(expr_a):
                        results.append((expr_a, target, "D2a"))

            # 尝试分解 a 和 b 本身（放在括号内更臭）
            if a <= 200 and b <= 200:
                ad = decompose_simple_sum(a, max_terms=3)
                bd = decompose_simple_sum(b, max_terms=3)
                if ad and bd:
                    a_expr = sum_decomp_to_expr(ad)
                    b_expr = sum_decomp_to_expr(bd)
                    r2 = target - 514 * a - 114 * b
                    if r2 == 0:
                        expr = f"514 × ({a_expr}) + 114 × ({b_expr})"
                        if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
                            results.append((expr, target, "D3"))
                    elif r2 > 0:
                        rd3 = decompose_simple_sum(r2, max_terms=3)
                        if rd3:
                            expr = f"514 × ({a_expr}) + 114 × ({b_expr}) + {sum_decomp_to_expr(rd3)}"
                            if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
                                results.append((expr, target, "D3"))

    return results


def strategy_E_14514_mul(target):
    """策略 E：14514 × k + r（近亲乘法变体）"""
    if target <= 14514:
        return []

    results = []
    base = 14514
    k = target // base
    r = target % base

    # E1
    if r == 0:
        expr = f"14514 × {k}"
    else:
        expr = f"14514 × {k} + {r}"
    if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
        results.append((expr, target, "E1"))

    # E2: 分解 k
    kd = decompose_simple_sum(k, max_terms=4)
    if kd:
        if r == 0:
            expr = f"14514 × ({sum_decomp_to_expr(kd)})"
        else:
            expr = f"14514 × ({sum_decomp_to_expr(kd)}) + {r}"
        if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
            results.append((expr, target, "E2"))

    # E3: 分解 r
    if r > 0:
        rd = decompose_simple_sum(r, max_terms=5)
        kd3 = decompose_simple_sum(k, max_terms=3)
        if kd3 and rd:
            expr = f"14514 × ({sum_decomp_to_expr(kd3)}) + {sum_decomp_to_expr(rd)}"
            if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
                results.append((expr, target, "E3"))

    return results


def strategy_F_division(target):
    """策略 F：(a × b) ÷ c + r（除法还原）"""
    results = []

    multipliers = [114514, 14514, 514, 114]
    divisors = [n for n in [5, 4, 11, 14, 15, 51, 54, 114, 514] if n != 1]

    for a in multipliers:
        if a > target * 10:
            continue
        for d in divisors:
            if d == 1 or d == 0:
                continue
            # find b such that (a * b) / d is close to target
            b_approx = target * d // a
            for b in range(max(1, b_approx - 3), b_approx + 4):
                prod = a * b
                if prod % d != 0:
                    continue
                val = prod // d
                if val == target:
                    expr = f"({a} × {b}) ÷ {d}"
                    if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
                        results.append((expr, target, "F"))
                elif abs(target - val) <= 2000:
                    r = target - val
                    if r > 0:
                        rd = decompose_simple_sum(r, max_terms=3)
                        if rd:
                            expr = f"({a} × {b}) ÷ {d} + {sum_decomp_to_expr(rd)}"
                            if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
                                results.append((expr, target, "F"))

    return results


def strategy_G_114514_base(target):
    """策略 G：114514 进制展开（学院派）"""
    if target < 114514:
        return []

    results = []
    base = 114514
    n = target
    digits = []
    while n > 0:
        d = n % base
        if d == 0:
            return []
        digits.append(d)
        n //= base

    parts = []
    ok = True
    for i, d in enumerate(digits):
        if has_digit_zero(d):
            ok = False
            break
        if i == 0:
            parts.append(str(d))
        elif i == 1:
            parts.append(f"{d} × 114514")
        else:
            parts.append(f"{d} × 114514^{i}")

    if ok and parts:
        expr = " + ".join(reversed(parts))
        if verify_no_zero_value(expr) and not expr_has_bad_patterns(expr):
            results.append((expr, target, "G"))

    return results


# =====================================================================
# 第五节：搜索编排与结果筛选
# =====================================================================

def search_all_strategies(target):
    """运行所有搜索策略，返回去重后的表达式列表"""
    all_exprs = []
    seen = set()

    def add_results(results):
        for expr, val, strat in results:
            norm = re.sub(r'\s+', '', expr)
            if norm not in seen:
                seen.add(norm)
                all_exprs.append((expr, val, strat))

    # 按顺序执行各策略
    add_results(strategy_A_direct_sum(target))
    add_results(strategy_B_114514_mul(target))
    add_results(strategy_D_514_114_mix(target))
    add_results(strategy_E_14514_mul(target))
    add_results(strategy_F_division(target))
    add_results(strategy_G_114514_base(target))

    # 大数补 C
    if target > 5000000:
        add_results(strategy_C_1145140_mul(target))

    return all_exprs


def rate_expression(expr_str):
    """
    评分函数，按 function.md 第 6 节规则。
    返回 (level, emoji, label, raw_score)
    """
    score = 0

    # 114 出现次数 (+2 each, max +6)
    c114 = count_standalone(expr_str, 114)
    score += min(c114 * 2, 6)

    # 514 出现次数 (+3 each, max +9)
    c514 = count_standalone(expr_str, 514)
    score += min(c514 * 3, 9)

    # 114514 完整出现 (+5 each, max +10)
    c114514 = count_standalone(expr_str, 114514)
    score += min(c114514 * 5, 10)

    # 运算复杂度
    has_power = '²' in expr_str or '³' in expr_str or '^' in expr_str
    score += 3 if has_power else 1

    # 表达式长度（超过 5 个运算符 → +1）
    ops = sum(1 for c in expr_str if c in '×÷＋−')
    if ops > 5:
        score += 1

    # 恶臭数占比
    numbers = re.findall(r'\d+', expr_str)
    stench_set = set(ALL_POOL_MEGA)
    nums_int = [int(n) for n in numbers]
    if nums_int:
        ratio = sum(1 for n in nums_int if n in stench_set) / len(nums_int)
        if ratio > 0.7:
            score += 2

    # 等级转换
    if score <= 2:
        level = max(1, score)
        emoji = "🫵"
        label = "不够臭啊"
    elif score <= 5:
        level = max(3, score - 1)
        emoji = "💨"
        label = "微微发臭"
    elif score <= 8:
        level = score - 1
        emoji = "🤢"
        label = "有点味道了"
    elif score <= 12:
        level = score - 4
        emoji = "💩"
        label = "恶臭来袭"
    elif score <= 16:
        level = 9
        emoji = "🔥"
        label = "非常恶臭"
    else:
        level = 10
        emoji = "🏆"
        label = "究极恶臭！"

    return level, emoji, label, score


def select_top_expressions(all_exprs, max_count=5):
    """按恶臭等级排序，去重后选择前 max_count 个"""
    if not all_exprs:
        return []

    scored = []
    seen_fingerprints = set()

    for expr, val, strategy in all_exprs:
        level, emoji, label, score = rate_expression(expr)

        # 指纹去重：排序后的数字列表
        nums = re.findall(r'\d+', expr)
        fingerprint = tuple(sorted(int(n) for n in nums))
        if fingerprint in seen_fingerprints:
            continue
        seen_fingerprints.add(fingerprint)

        scored.append((expr, val, strategy, level, emoji, label, score))

    # 排序：等级降序 → 评分降序 → 表达式短优先
    scored.sort(key=lambda x: (-x[3], -x[6], len(x[0])))
    return scored[:max_count]


