def decompose_remainder(r, max_depth=3):
    """
    将余数 r 分解为 a × b + c 形式（高级恶臭分解）。
    返回表达式字符串（不含 0 数码位，不含双负号），或 None。
    """
    if r <= 0:
        return None
    if has_digit_zero(r):
        pass  # 需要进一步分解
    else:
        # r 本身不含 0 数码位，原样返回
        pass

    candidates = []

    # 方法1: a × b = r
    for a in reversed(ALL_POOL):
        if a == 0 or a > r:
            continue
        for b in reversed(ALL_POOL):
            if b == 0:
                continue
            prod = a * b
            if prod == r:
                cand = f"{a} × {b}"
                if not expr_has_bad_patterns(cand):
                    return cand  # 最佳情况

    # 方法2: a × b + c = r (c 小)
    for a in reversed(ALL_POOL):
        if a == 0 or a > r:
            continue
        for b in reversed(ALL_POOL):
            if b == 0:
                continue
            prod = a * b
            if prod >= r:
                continue
            c = r - prod
            if has_digit_zero(c):
                # 尝试进一步分解 c
                c_sub = decompose_remainder(c, max_depth - 1)
                if c_sub:
                    cand = f"{a} × {b} + {c_sub}"
                    if not expr_has_bad_patterns(cand):
                        candidates.append(cand)
            else:
                cand = f"{a} × {b} + {c}"
                if not expr_has_bad_patterns(cand):
                    candidates.append(cand)

    # 方法3: a × b − c = r (r + c = a × b, c 小)
    for a in reversed(ALL_POOL):
        if a == 0:
            continue
        for b in reversed(ALL_POOL):
            if b == 0:
                continue
            prod = a * b
            if prod <= r:
                continue
            c = prod - r
            if has_digit_zero(c):
                continue
            cand = f"{a} × {b} − {c}"
            if not expr_has_bad_patterns(cand):
                candidates.append(cand)

    if not candidates:
        return None
    # 按长度排序（短的优先）
    candidates.sort(key=len)
    return candidates[0]

