    usable_a = [n for n in reversed(ALL_POOL) if n <= r]

    # 方法1: a × b = r （完美匹配）
    for a in usable_a:
        for b in ALL_POOL:
            if b == 0:
                continue
            prod = a * b
            if prod == r:
                cand = f"{a} × {b}"
                if not expr_has_bad_patterns(cand):
                    return cand  # 最佳情况
            if prod > r:
                break

    # 方法2: a × b + c = r (c ≤ 2000，小修正)
    if max_depth > 0:
        for a in usable_a:
            max_b = min(r // a + 1, 200)
            for b in ALL_POOL:
                if b == 0 or b > max_b:
                    continue
                prod = a * b
                if prod >= r:
                    continue
                c = r - prod
                if c > 2000:
                    continue  # 余数太大，不好
                if has_digit_zero(c) and max_depth > 1:
                    c_sub = decompose_remainder(c, max_depth - 1)
                    if c_sub:
                        cand = f"{a} × {b} + {c_sub}"
                        if not expr_has_bad_patterns(cand):
                            candidates.append(cand)
                elif not has_digit_zero(c):
                    cand = f"{a} × {b} + {c}"
                    if not expr_has_bad_patterns(cand):
                        candidates.append(cand)

        # 方法3: a × b − c = r (c ≤ 2000)
        for a in usable_a:
            min_b = r // a + 1
            for b in ALL_POOL:
                if b == 0 or b < min_b:
                    continue
                prod = a * b
                if prod <= r:
                    continue
                c = prod - r
                if c > 2000:
                    continue
                if has_digit_zero(c):
                    continue
                cand = f"{a} × {b} − {c}"
                if not expr_has_bad_patterns(cand):
                    candidates.append(cand)

    # 方法4: 纯加法分解（兜底）
    if r > 0 and not has_digit_zero(r) and max_depth > 0:
        s_decomp = decompose_simple_sum(r, max_terms=6)
        if s_decomp:
            cand = sum_decomp_to_expr(s_decomp)
            if not expr_has_bad_patterns(cand):
                candidates.append(cand)

    if not candidates:
        return None
    # 排序：长的优先（更多恶臭数）
    candidates.sort(key=len, reverse=True)
    return candidates[0]

